using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.StartsWith("(212)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.EndsWith("1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedPattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
        Assert.AreEqual("digits", ex.ParamName);
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ReturnsGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Williams", "Ms.");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson", "Prof.");

        Assert.Contains("Anderson", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhiteSpaceName_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithPrefix_StartsWithExpectedSlug()
    {
        var result = _formatter.GenerateSlug("Getting Started with MSTest");

        Assert.StartsWith("getting-started", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSuffix_EndsWithExpectedSlug()
    {
        var result = _formatter.GenerateSlug("Introduction to Unit Testing");

        Assert.EndsWith("unit-testing", result);
    }

    [TestMethod]
    public void GenerateSlug_OnlyContainsValidCharacters()
    {
        var result = _formatter.GenerateSlug("C# is Great! (Really)");

        Assert.MatchesRegex(@"^[a-z0-9\-]+$", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_ReplacedWithHyphens()
    {
        var result = _formatter.GenerateSlug("foo & bar");

        Assert.Contains("-", result);
        Assert.StartsWith("foo", result);
        Assert.EndsWith("bar", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_TrimmedCleanly()
    {
        var result = _formatter.GenerateSlug("  padded title  ");

        Assert.AreEqual("padded-title", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhiteSpace_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(title!));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(42.50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(9.5m, "£");

        Assert.AreEqual("£9.50", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_MatchesPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        Assert.Contains("-", result);
    }
}

