    public void GenerateSlug_TitleWithPrefix_StartsWithExpectedSlug()
    {
        var result = _formatter.GenerateSlug("Getting Started with MSTest");

        Assert.StartsWith("getting-started", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSuffix_EndsWithExpectedSlug()
    {
        var result = _formatter.GenerateSlug("Introduction to Unit Testing");

        Assert.EndsWith("unit-testing", result);
    }

